from flask import Flask, request, jsonify
import numpy as np

app = Flask(__name__)

# In-memory storage for image labels
image_labels = {}

@app.route('/label', methods=['POST'])
def label_image():
    data = request.json
    image_id = data['image_id']
    label = data['label']

    if image_id not in image_labels:
        image_labels[image_id] = []

    image_labels[image_id].append(label)

    return jsonify({'status': 'success'}), 200

@app.route('/aggregate', methods=['GET'])
def aggregate_labels():
    aggregated_labels = {}

    for image_id, labels in image_labels.items():
        if len(labels) > 0:
            majority_label = max(set(labels), key=labels.count)
            aggregated_labels[image_id] = majority_label
        else:
            aggregated_labels[image_id] = None

    return jsonify(aggregated_labels)

@app.route('/train', methods=['POST'])
def train_model():
    data = request.json
    labels = data['labels']
    features = data['features']

    # Simple model training using majority voting for demonstration purposes
    if len(labels) > 0:
        majority_label = max(set(labels), key=labels.count)
        print(f"Model trained with label: {majority_label}")
    else:
        print("No labels to train the model")

    return jsonify({'status': 'success'}), 200

if __name__ == '__main__':
    app.run(debug=True)